class Solution {
public:
    int findLHS(vector<int>& nums) {
        unordered_map<int,int> cnt;
        for (int x : nums) cnt[x]++;
        int ans = 0;
        for (auto& p : cnt)
            if (cnt.count(p.first+1))
                ans = max(ans, p.second + cnt[p.first+1]);
        return ans;
    }
};
